/// Turn a switch on a ucmp/scmp intrinsic into a comparison and branch.
/// The ucmp/scmp intrinsic returns -1 (less), 0 (equal), or 1 (greater).
/// When the switch only has two destinations, we can convert to icmp + br.
bool SimplifyCFGOpt::turnSwitchOnCmpIntrinsicToICmp(SwitchInst *SI,
                                                    IRBuilder<> &Builder) {
  // Check if the switch condition is a ucmp or scmp intrinsic.
  auto *II = dyn_cast<IntrinsicInst>(SI->getCondition());
  if (!II)
    return false;

  Intrinsic::ID ID = II->getIntrinsicID();
  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
    return false;

  // ucmp/scmp returns -1, 0, or 1. The switch must have exactly 2 destinations.
  Value *Op0 = II->getArgOperand(0);
  Value *Op1 = II->getArgOperand(1);

  BasicBlock *DefaultDest = SI->getDefaultDest();
  bool HasDefault = !isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg());

  // Partition the cases into two sets with different destinations.
  BasicBlock *DestA = nullptr;
  BasicBlock *DestB = nullptr;
  SmallVector<ConstantInt *, 4> CasesA, CasesB;

  for (auto Case : SI->cases()) {
    BasicBlock *Dest = Case.getCaseSuccessor();
    if (!DestA) {
      DestA = Dest;
      CasesA.push_back(Case.getCaseValue());
      continue;
    }
    if (Dest == DestA) {
      CasesA.push_back(Case.getCaseValue());
      continue;
    }
    if (!DestB) {
      DestB = Dest;
      CasesB.push_back(Case.getCaseValue());
      continue;
    }
    if (Dest == DestB) {
      CasesB.push_back(Case.getCaseValue());
      continue;
    }
    return false; // More than two destinations.
  }
  if (!DestB)
    return false; // All destinations are the same

  assert(DestA != DestB);

  // Determine which case values go to which destination.
  // For ucmp/scmp, the result is:
  //   -1 if Op0 < Op1 (ult/slt)
  //    0 if Op0 == Op1 (eq)
  //    1 if Op0 > Op1 (ugt/sgt)
  //
  // Values not explicitly in cases go to the default destination.

  BasicBlock *DestForNegOne, *DestForZero, *DestForOne;

  // Find destination for -1
  bool FoundNegOne = false;
  for (auto *C : CasesA) if (C->getSExtValue() == -1) { DestForNegOne = DestA; FoundNegOne = true; break; }
  if (!FoundNegOne) {
    for (auto *C : CasesB) if (C->getSExtValue() == -1) { DestForNegOne = DestB; FoundNegOne = true; break; }
  }
  if (!FoundNegOne) DestForNegOne = DefaultDest;

  // Find destination for 0
  bool FoundZero = false;
  for (auto *C : CasesA) if (C->getSExtValue() == 0) { DestForZero = DestA; FoundZero = true; break; }
  if (!FoundZero) {
    for (auto *C : CasesB) if (C->getSExtValue() == 0) { DestForZero = DestB; FoundZero = true; break; }
  }
  if (!FoundZero) DestForZero = DefaultDest;

  // Find destination for 1
  bool FoundOne = false;
  for (auto *C : CasesA) if (C->getSExtValue() == 1) { DestForOne = DestA; FoundOne = true; break; }
  if (!FoundOne) {
    for (auto *C : CasesB) if (C->getSExtValue() == 1) { DestForOne = DestB; FoundOne = true; break; }
  }
  if (!FoundOne) DestForOne = DefaultDest;

  // Determine the icmp predicate based on which destination gets which values.
  ICmpInst::Predicate Pred;
  BasicBlock *TrueDest, *FalseDest;

  if (ID == Intrinsic::ucmp) {
    // Unsigned comparison: -1=ult, 0=eq, 1=ugt
    if (DestForOne != DestForNegOne || DestForOne != DestForZero) {
      // ugt pattern: 1 goes to one dest, {-1,0} to other
      if (DestForOne == DestForNegOne) {
        // {1, -1} vs {0} -> ne vs eq
        Pred = ICmpInst::ICMP_NE;
        TrueDest = DestForOne;
        FalseDest = DestForZero;
      } else if (DestForOne == DestForZero) {
        // {1, 0} vs {-1} -> uge vs ult
        Pred = ICmpInst::ICMP_UGE;
        TrueDest = DestForOne;
        FalseDest = DestForNegOne;
      } else {
        // {1} vs {-1, 0} -> ugt vs ule
        Pred = ICmpInst::ICMP_UGT;
        TrueDest = DestForOne;
        FalseDest = DestForNegOne;
      }
    } else if (DestForNegOne != DestForZero) {
      // {-1} vs {0} with 1 going same as one of them
      if (DestForOne == DestForNegOne) {
        // {-1, 1} vs {0} -> ne vs eq
        Pred = ICmpInst::ICMP_NE;
        TrueDest = DestForNegOne;
        FalseDest = DestForZero;
      } else {
        // {-1} vs {0, 1} -> ult vs uge
        Pred = ICmpInst::ICMP_ULT;
        TrueDest = DestForNegOne;
        FalseDest = DestForZero;
      }
    } else {
      // All three values go to different destinations - shouldn't happen with 2 dests
      return false;
    }
  } else {
    // Signed comparison: -1=slt, 0=eq, 1=sgt
    if (DestForOne != DestForNegOne || DestForOne != DestForZero) {
      if (DestForOne == DestForNegOne) {
        Pred = ICmpInst::ICMP_NE;
        TrueDest = DestForOne;
        FalseDest = DestForZero;
      } else if (DestForOne == DestForZero) {
        Pred = ICmpInst::ICMP_SGE;
        TrueDest = DestForOne;
        FalseDest = DestForNegOne;
      } else {
        Pred = ICmpInst::ICMP_SGT;
        TrueDest = DestForOne;
        FalseDest = DestForNegOne;
      }
    } else if (DestForNegOne != DestForZero) {
      if (DestForOne == DestForNegOne) {
        Pred = ICmpInst::ICMP_NE;
        TrueDest = DestForNegOne;
        FalseDest = DestForZero;
      } else {
        Pred = ICmpInst::ICMP_SLT;
        TrueDest = DestForNegOne;
        FalseDest = DestForZero;
      }
    } else {
      return false;
    }
  }

  // Build the new icmp and branch.
  Value *Cmp = Builder.CreateICmp(Pred, Op0, Op1, "cmp");
  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);

  // Copy branch weights if present.
  if (hasBranchWeightMD(*SI)) {
    SmallVector<uint64_t, 8> Weights;
    getBranchWeights(SI, Weights);
    if (Weights.size() == 1 + SI->getNumCases()) {
      uint64_t TrueWeight = 0, FalseWeight = 0;
      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
        if (SI->getSuccessor(I) == TrueDest)
          TrueWeight += Weights[I];
        else
          FalseWeight += Weights[I];
      }
      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
        TrueWeight /= 2;
        FalseWeight /= 2;
      }
      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
    }
  }

  // Update PHI nodes in the destination blocks.
  auto UpdatePHIs = [&](BasicBlock *Dest, bool IsTrue) {
    for (auto BBI = Dest->begin(); isa<PHINode>(BBI); ++BBI) {
      auto *PN = cast<PHINode>(BBI);
      // Count edges from SI's parent to this dest
      unsigned IncomingEdges = 0;
      if (Dest == DefaultDest) ++IncomingEdges; // default edge
      for (auto Case : SI->cases())
        if (Case.getCaseSuccessor() == Dest) ++IncomingEdges;
      // Remove all but one incoming edge
      for (unsigned I = 0, E = IncomingEdges - 1; I != E; ++I)
        PN->removeIncomingValue(SI->getParent());
    }
  };
  UpdatePHIs(TrueDest, true);
  UpdatePHIs(FalseDest, false);

  // Handle unreachable default.
  if (!HasDefault)
    createUnreachableSwitchDefault(SI, DTU);

  auto *UnreachableDefault = SI->getDefaultDest();
  auto *BB = SI->getParent();

  // Erase the switch.
  SI->eraseFromParent();

  if (!HasDefault && DTU)
    DTU->applyUpdates({{DominatorTree::Delete, BB, UnreachableDefault}});

  return true;
}
CODEEOF"}

